1	/* ============================================================
2	   MAXIWORX 2026 — Design System
3	   "Where Nature Distills High-End Tech"
4	   
5	   Autor:    Lead Developer
6	   Stack:    Vanilla CSS, XAMPP/Apache, PHP 8.5+
7	   Version:  1.0.0
8	   ============================================================ */
9	
10	/* ------------------------------------------------------------
11	   1. GOOGLE FONTS IMPORT
12	   ------------------------------------------------------------ */
13	@import url('https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,300;0,400;0,500;0,600;1,300;1,400;1,500&family=Inter:wght@300;400;500;600&family=Cormorant:ital,wght@0,300;1,300&display=swap');
14	
15	
16	/* ------------------------------------------------------------
17	   2. CSS CUSTOM PROPERTIES (Design Tokens)
18	   ------------------------------------------------------------ */
19	:root {
20	
21	  /* --- Farben: Basis --- */
22	  --color-bg-base:        #080808;   /* Tiefstes Schwarz — Haupt-Hintergrund */
23	  --color-bg-deep:        #0D0D0D;   /* Hintergrund fixiert (parallax layer) */
24	  --color-bg-card:        #141414;   /* Cards, Sektionen */
25	  --color-bg-card-hover:  #1C1C1C;   /* Card hover state */
26	  --color-bg-surface:     #1A1A1A;   /* Surfaces, modals */
27	  --color-bg-input:       #111111;   /* Formularfelder */
28	  --color-bg-overlay:     rgba(8, 8, 8, 0.75); /* Overlay über Hintergrundbild */
29	
30	  /* --- Farben: Text --- */
31	  --color-text-primary:   #F0EDE8;   /* Headlines — warmes Weiß */
32	  --color-text-secondary: #A8A49E;   /* Subheadlines, Labels */
33	  --color-text-muted:     #5C5955;   /* Muted text, Metadaten */
34	  --color-text-inverse:   #0A0A0A;   /* Text auf hellen Flächen */
35	
36	  /* --- Farben: Akzent Gold (Kern-Identität) --- */
37	  --color-gold:           #C8922A;   /* Primärer Gold-Akzent */
38	  --color-gold-light:     #D4A843;   /* Hover, highlights */
39	  --color-gold-dim:       #8A6420;   /* Subtle gold (borders, dividers) */
40	  --color-gold-glow:      rgba(200, 146, 42, 0.15); /* Gold glow effect */
41	  --color-gold-glow-strong: rgba(200, 146, 42, 0.30);
42	
43	  /* --- Farben: Blau (Tech-Akzent, nur CTA) --- */
44	  --color-blue:           #3A7BD5;   /* CTA Button */
45	  --color-blue-hover:     #4A8BE5;
46	  --color-blue-glow:      rgba(58, 123, 213, 0.20);
47	
48	  /* --- Farben: Borders --- */
49	  --color-border:         rgba(255, 255, 255, 0.06);
50	  --color-border-hover:   rgba(255, 255, 255, 0.12);
51	  --color-border-gold:    rgba(200, 146, 42, 0.25);
52	  --color-border-gold-strong: rgba(200, 146, 42, 0.50);
53	
54	  /* --- Glassmorphism --- */
55	  --glass-bg:             rgba(20, 20, 20, 0.60);
56	  --glass-bg-light:       rgba(30, 30, 30, 0.40);
57	  --glass-blur:           blur(20px);
58	  --glass-blur-heavy:     blur(40px);
59	  --glass-border:         1px solid rgba(255, 255, 255, 0.08);
60	  --glass-border-gold:    1px solid rgba(200, 146, 42, 0.20);
61	
62	  /* --- Typografie: Familien --- */
63	  --font-display:   'Cormorant Garamond', 'Georgia', serif;   /* Headlines, Logo */
64	  --font-body:      'Inter', 'Helvetica Neue', sans-serif;    /* UI, Body-Text */
65	  --font-caption:   'Cormorant', 'Georgia', serif;            /* Kursiv-Captions */
66	
67	  /* --- Typografie: Größen (fluid clamp-basiert) --- */
68	  --text-xs:        0.688rem;   /* 11px */
69	  --text-sm:        0.813rem;   /* 13px */
70	  --text-base:      0.938rem;   /* 15px */
71	  --text-md:        1.063rem;   /* 17px */
72	  --text-lg:        1.25rem;    /* 20px */
73	  --text-xl:        1.5rem;     /* 24px */
74	  --text-2xl:       2rem;       /* 32px */
75	  --text-3xl:       clamp(2.5rem, 5vw, 4rem);      /* ~40-64px */
76	  --text-4xl:       clamp(3.5rem, 7vw, 6rem);      /* ~56-96px */
77	  --text-hero:      clamp(4rem,  10vw, 8.5rem);    /* Hero-Titel */
78	
79	  /* --- Typografie: Gewichte --- */
80	  --weight-light:   300;
81	  --weight-regular: 400;
82	  --weight-medium:  500;
83	  --weight-semibold:600;
84	
85	  /* --- Spacing --- */
86	  --space-1:  0.25rem;   /*  4px */
87	  --space-2:  0.5rem;    /*  8px */
88	  --space-3:  0.75rem;   /* 12px */
89	  --space-4:  1rem;      /* 16px */
90	  --space-5:  1.25rem;   /* 20px */
91	  --space-6:  1.5rem;    /* 24px */
92	  --space-8:  2rem;      /* 32px */
93	  --space-10: 2.5rem;    /* 40px */
94	  --space-12: 3rem;      /* 48px */
95	  --space-16: 4rem;      /* 64px */
96	  --space-20: 5rem;      /* 80px */
97	  --space-24: 6rem;      /* 96px */
98	  --space-32: 8rem;      /* 128px */
99	
100	  /* --- Border Radius --- */
101	  --radius-sm:   4px;
102	  --radius-md:   8px;
103	  --radius-lg:   12px;
104	  --radius-xl:   20px;
105	  --radius-full: 9999px;
106	
107	  /* --- Shadows --- */
108	  --shadow-sm:    0 1px 3px rgba(0,0,0,0.40);
109	  --shadow-md:    0 4px 16px rgba(0,0,0,0.50);
110	  --shadow-lg:    0 8px 32px rgba(0,0,0,0.60);
111	  --shadow-xl:    0 16px 64px rgba(0,0,0,0.70);
112	  --shadow-gold:  0 4px 24px rgba(200, 146, 42, 0.20);
113	  --shadow-gold-strong: 0 8px 40px rgba(200, 146, 42, 0.35);
114	
115	  /* --- Transitions --- */
116	  --transition-fast:   150ms cubic-bezier(0.4, 0, 0.2, 1);
117	  --transition-base:   250ms cubic-bezier(0.4, 0, 0.2, 1);
118	  --transition-slow:   400ms cubic-bezier(0.4, 0, 0.2, 1);
119	  --transition-spring: 500ms cubic-bezier(0.34, 1.56, 0.64, 1);
120	
121	  /* --- Layout --- */
122	  --container-max:   1280px;
123	  --container-wide:  1440px;
124	  --nav-height:      64px;
125	  --nav-height-scrolled: 52px;
126	
127	  /* --- Z-Index Skala --- */
128	  --z-base:     0;
129	  --z-above:    10;
130	  --z-overlay:  20;
131	  --z-modal:    30;
132	  --z-nav:      40;
133	  --z-toast:    50;
134	
135	  /* --- Bento Grid --- */
136	  --bento-gap:  16px;
137	  --bento-gap-sm: 10px;
138	}
139	
140	
141	/* ------------------------------------------------------------
142	   3. CSS RESET & BASE
143	   ------------------------------------------------------------ */
144	*, *::before, *::after {
145	  box-sizing: border-box;
146	  margin: 0;
147	  padding: 0;
148	}
149	
150	html {
151	  scroll-behavior: smooth;
152	  font-size: 16px;
153	  -webkit-text-size-adjust: 100%;
154	  text-size-adjust: 100%;
155	}
156	
157	body {
158	  background-color: var(--color-bg-base);
159	  color: var(--color-text-primary);
160	  font-family: var(--font-body);
161	  font-size: var(--text-base);
162	  font-weight: var(--weight-regular);
163	  line-height: 1.6;
164	  -webkit-font-smoothing: antialiased;
165	  -moz-osx-font-smoothing: grayscale;
166	  overflow-x: hidden;
167	}
168	
169	img, video {
170	  display: block;
171	  max-width: 100%;
172	  height: auto;
173	}
174	
175	a {
176	  color: inherit;
177	  text-decoration: none;
178	}
179	
180	button {
181	  cursor: pointer;
182	  border: none;
183	  background: none;
184	  font-family: inherit;
185	}
186	
187	input, textarea, select {
188	  font-family: inherit;
189	  font-size: inherit;
190	  color: inherit;
191	}
192	
193	ul, ol {
194	  list-style: none;
195	}
196	
197	::selection {
198	  background: var(--color-gold-glow-strong);
199	  color: var(--color-gold-light);
200	}
201	
202	/* Scrollbar Styling */
203	::-webkit-scrollbar {
204	  width: 6px;
205	  height: 6px;
206	}
207	::-webkit-scrollbar-track {
208	  background: var(--color-bg-base);
209	}
210	::-webkit-scrollbar-thumb {
211	  background: var(--color-gold-dim);
212	  border-radius: var(--radius-full);
213	}
214	::-webkit-scrollbar-thumb:hover {
215	  background: var(--color-gold);
216	}
217	
218	
219	/* ------------------------------------------------------------
220	   4. TYPOGRAFIE-SYSTEM
221	   ------------------------------------------------------------ */
222	
223	/* Display / Hero */
224	.t-hero {
225	  font-family: var(--font-display);
226	  font-size: var(--text-hero);
227	  font-weight: var(--weight-light);
228	  letter-spacing: 0.15em;
229	  text-transform: uppercase;
230	  line-height: 1.0;
231	  color: var(--color-text-primary);
232	}
233	
234	.t-display {
235	  font-family: var(--font-display);
236	  font-size: var(--text-4xl);
237	  font-weight: var(--weight-light);
238	  letter-spacing: 0.04em;
239	  line-height: 1.1;
240	  color: var(--color-text-primary);
241	}
242	
243	.t-heading {
244	  font-family: var(--font-display);
245	  font-size: var(--text-3xl);
246	  font-weight: var(--weight-light);
247	  letter-spacing: 0.02em;
248	  line-height: 1.15;
249	  color: var(--color-text-primary);
250	}
251	
252	.t-subheading {
253	  font-family: var(--font-display);
254	  font-size: var(--text-xl);
255	  font-weight: var(--weight-regular);
256	  letter-spacing: 0.01em;
257	  line-height: 1.3;
258	  color: var(--color-text-primary);
259	}
260	
261	/* Tagline (kursiv, gold) */
262	.t-tagline {
263	  font-family: var(--font-display);
264	  font-style: italic;
265	  font-size: clamp(0.875rem, 2vw, 1.125rem);
266	  font-weight: var(--weight-light);
267	  letter-spacing: 0.25em;
268	  text-transform: uppercase;
269	  color: var(--color-gold);
270	  line-height: 1.4;
271	}
272	
273	/* Label / Overline (Kategorie-Labels, z.B. "PORTFOLIO") */
274	.t-label {
275	  font-family: var(--font-body);
276	  font-size: var(--text-xs);
277	  font-weight: var(--weight-medium);
278	  letter-spacing: 0.20em;
279	  text-transform: uppercase;
280	  color: var(--color-gold);
281	  line-height: 1.4;
282	}
283	
284	/* Body Text */
285	.t-body {
286	  font-family: var(--font-body);
287	  font-size: var(--text-base);
288	  font-weight: var(--weight-light);
289	  line-height: 1.75;
290	  color: var(--color-text-secondary);
291	}
292	
293	.t-body-sm {
294	  font-family: var(--font-body);
295	  font-size: var(--text-sm);
296	  font-weight: var(--weight-light);
297	  line-height: 1.65;
298	  color: var(--color-text-secondary);
299	}
300	
301	/* Nav Text */
302	.t-nav {
303	  font-family: var(--font-body);
304	  font-size: var(--text-sm);
305	  font-weight: var(--weight-medium);
306	  letter-spacing: 0.06em;
307	  text-transform: uppercase;
308	  color: var(--color-text-secondary);
309	}
310	
311	/* Caption (kursiv serif) */
312	.t-caption {
313	  font-family: var(--font-caption);
314	  font-style: italic;
315	  font-size: var(--text-sm);
316	  font-weight: var(--weight-light);
317	  color: var(--color-text-muted);
318	  letter-spacing: 0.02em;
319	}
320	
321	/* Muted */
322	.t-muted {
323	  color: var(--color-text-muted);
324	}
325	
326	/* Gold highlight */
327	.t-gold {
328	  color: var(--color-gold);
329	}
330	
331	
332	/* ------------------------------------------------------------
333	   5. LAYOUT UTILITIES
334	   ------------------------------------------------------------ */
335	.container {
336	  width: 100%;
337	  max-width: var(--container-max);
338	  margin-inline: auto;
339	  padding-inline: var(--space-6);
340	}
341	
342	.container--wide {
343	  max-width: var(--container-wide);
344	  padding-inline: var(--space-8);
345	}
346	
347	.container--narrow {
348	  max-width: 860px;
349	}
350	
351	/* Section Padding */
352	.section {
353	  padding-block: var(--space-24);
354	  position: relative;
355	}
356	
357	.section--lg {
358	  padding-block: var(--space-32);
359	}
360	
361	.section--sm {
362	  padding-block: var(--space-16);
363	}
364	
365	/* Flex helpers */
366	.flex       { display: flex; }
367	.flex-col   { flex-direction: column; }
368	.items-center { align-items: center; }
369	.justify-between { justify-content: space-between; }
370	.gap-4      { gap: var(--space-4); }
371	.gap-6      { gap: var(--space-6); }
372	.gap-8      { gap: var(--space-8); }
373	
374	
375	/* ------------------------------------------------------------
376	   6. PARALLAX / FIXED BACKGROUND SYSTEM
377	   ------------------------------------------------------------ */
378	
379	/* Der fixierte Hintergrund bleibt an Ort und Stelle.
380	   Inhalts-Sektionen "floaten" darüber beim Scrollen. */
381	.bg-fixed-layer,
382	.bg-fixed {
383	  position: fixed;
384	  inset: 0;
385	  z-index: var(--z-base);
386	  background-color: var(--color-bg-deep);
387	  /* Echtes Foto: background-image: url('../images/studio-bg.jpg'); */
388	  background-image:
389	    radial-gradient(ellipse 80% 60% at 50% 30%,
390	      rgba(200, 146, 42, 0.04) 0%,
391	      transparent 60%),
392	    radial-gradient(ellipse 60% 80% at 20% 80%,
393	      rgba(58, 123, 213, 0.03) 0%,
394	      transparent 50%),
395	    linear-gradient(
396	      160deg,
397	      #0A0A08 0%,
398	      #0E0E0C 25%,
399	      #101010 50%,
400	      #0C0C0A 75%,
401	      #080808 100%
402	    );
403	  background-size: cover;
404	  background-position: center top;
405	  background-attachment: fixed;
406	}
407	
408	/* Overlay für Lesbarkeit über dem Hintergrundfoto */
409	.bg-fixed-layer::after,
410	.bg-fixed::after {
411	  content: '';
412	  position: absolute;
413	  inset: 0;
414	  background: var(--color-bg-overlay);
415	}
416	
417	/* Alle Sektions-Inhalte liegen über dem fixierten BG */
418	.site-content {
419	  position: relative;
420	  z-index: var(--z-above);
421	}
422	
423	/* Sektionen mit eigenem Hintergrund (Cards-Bereiche) */
424	.section--opaque {
425	  background: var(--color-bg-card);
426	}
427	
428	.section--glass {
429	  background: var(--glass-bg);
430	  backdrop-filter: var(--glass-blur);
431	  -webkit-backdrop-filter: var(--glass-blur);
432	  border-top: var(--glass-border);
433	  border-bottom: var(--glass-border);
434	}
435	
436	
437	/* ------------------------------------------------------------
438	   7. NAVIGATION
439	   ------------------------------------------------------------ */
440	.site-nav {
441	  position: fixed;
442	  top: 12px;
443	  left: 12px;
444	  right: 12px;
445	  z-index: var(--z-nav);
446	  height: var(--nav-height);
447	  display: flex;
448	  align-items: center;
449	  border-radius: var(--radius-xl);
450	
451	  /* Pill permanent sichtbar — starker Glaseffekt + sichtbarer Rahmen */
452	  background: rgba(12, 12, 10, 0.28);
453	  backdrop-filter: blur(28px) saturate(1.4);
454	  -webkit-backdrop-filter: blur(28px) saturate(1.4);
455	  border: 1px solid rgba(255, 255, 255, 0.10);
456	  box-shadow: 0 4px 24px rgba(0, 0, 0, 0.35), inset 0 1px 0 rgba(255, 255, 255, 0.05);
457	
458	  transition: height      var(--transition-slow),
459	              background  var(--transition-slow),
460	              box-shadow  var(--transition-slow),
461	              top         var(--transition-slow);
462	}
463	
464	/* Transparente Nav im Hero-Bereich — nicht mehr benötigt, aber als Fallback */
465	.site-nav--transparent {
466	  background: rgba(12, 12, 10, 0.45);
467	}
468	
469	/* Stärkere Verglasung beim Scrollen — nav.js adds .nav--scrolled */
470	.site-nav--scrolled,
471	.site-nav.nav--scrolled {
472	  height: var(--nav-height-scrolled);
473	  top: 8px;
474	  background: rgba(12, 12, 10, 0.82);
475	  backdrop-filter: blur(32px) saturate(1.5);
476	  -webkit-backdrop-filter: blur(32px) saturate(1.5);
477	  border-color: rgba(255, 255, 255, 0.10);
478	  box-shadow: 0 8px 40px rgba(0, 0, 0, 0.5), inset 0 1px 0 rgba(255, 255, 255, 0.06);
479	}
480	
481	.nav-inner {
482	  width: 100%;
483	  max-width: var(--container-max);
484	  margin-inline: auto;
485	  padding-inline: var(--space-6);
486	  display: flex;
487	  align-items: center;
488	  justify-content: space-between;
489	  gap: var(--space-8);
490	}
491	
492	/* Logo */
493	.nav-logo {
494	  font-family: var(--font-display);
495	  font-size: 1.25rem;
496	  font-weight: var(--weight-medium);
497	  letter-spacing: 0.12em;
498	  text-transform: uppercase;
499	  color: var(--color-text-primary);
500	  white-space: nowrap;
501	  transition: opacity var(--transition-base);
502	}
503	
504	/* Nav-Titel-Integration (erscheint beim Scrollen) */
505	.nav-hero-title {
506	  display: flex;
507	  flex-direction: column;
508	  align-items: flex-start;
509	  overflow: hidden;
510	  max-height: 0;
511	  opacity: 0;
512	  transition:
513	    max-height var(--transition-slow),
514	    opacity var(--transition-slow);
515	}
516	
517	.site-nav--scrolled .nav-hero-title {
518	  max-height: 40px;
519	  opacity: 1;
520	}
521	
522	.nav-hero-title .title {
523	  font-family: var(--font-display);
524	  font-size: var(--text-xs);
525	  font-weight: var(--weight-medium);
526	  letter-spacing: 0.18em;
527	  text-transform: uppercase;
528	  color: var(--color-text-primary);
529	  line-height: 1.2;
530	}
531	
532	.nav-hero-title .tagline {
533	  font-family: var(--font-display);
534	  font-style: italic;
535	  font-size: 0.625rem;
536	  letter-spacing: 0.14em;
537	  text-transform: uppercase;
538	  color: var(--color-gold);
539	  line-height: 1.2;
540	}
541	
542	/* Nav Links */
543	.nav-links {
544	  display: flex;
545	  align-items: center;
546	  gap: var(--space-6);
547	}
548	
549	.nav-link {
550	  font-family: var(--font-body);
551	  font-size: var(--text-xs);
552	  font-weight: var(--weight-medium);
553	  letter-spacing: 0.10em;
554	  text-transform: uppercase;
555	  color: var(--color-text-secondary);
556	  transition: color var(--transition-fast);
557	  position: relative;
558	  padding-block: var(--space-1);
559	}
560	
561	.nav-link::after {
562	  content: '';
563	  position: absolute;
564	  bottom: -2px;
565	  left: 0;
566	  width: 0;
567	  height: 1px;
568	  background: var(--color-gold);
569	  transition: width var(--transition-base);
570	}
571	
572	.nav-link:hover {
573	  color: var(--color-text-primary);
574	}
575	
576	.nav-link:hover::after,
577	.nav-link.active::after {
578	  width: 100%;
579	}
580	
581	.nav-link.active {
582	  color: var(--color-text-primary);
583	}
584	
585	/* CTA Button */
586	.btn-nav-cta {
587	  font-family: var(--font-body);
588	  font-size: var(--text-xs);
589	  font-weight: var(--weight-medium);
590	  letter-spacing: 0.10em;
591	  text-transform: uppercase;
592	  color: #ffffff;
593	  background: var(--color-blue);
594	  border: 1px solid var(--color-blue);
595	  border-radius: var(--radius-full);
596	  padding: var(--space-2) var(--space-5);
597	  transition:
598	    background var(--transition-fast),
599	    box-shadow var(--transition-fast),
600	    transform var(--transition-fast);
601	  white-space: nowrap;
602	}
603	
604	.btn-nav-cta:hover {
605	  background: var(--color-blue-hover);
606	  box-shadow: var(--color-blue-glow) 0 4px 20px;
607	  transform: translateY(-1px);
608	}
609	
610	.btn-nav-cta:active {
611	  transform: translateY(0);
612	}
613	
614	
615	/* ------------------------------------------------------------
616	   8. HERO SECTION
617	   ------------------------------------------------------------ */
618	.hero {
619	  position: relative;
620	  min-height: 100svh;
621	  display: flex;
622	  flex-direction: column;
623	  align-items: center;
624	  justify-content: center;
625	  text-align: center;
626	  /* Nav ist jetzt 12px vom Rand entfernt → extra Offset */
627	  padding-top: calc(var(--nav-height) + 12px);
628	  overflow: hidden;
629	}
630	
631	.hero-content {
632	  position: relative;
633	  z-index: 2;
634	  display: flex;
