756	.bento-item--image .bento-image {
757	  position: absolute;
758	  inset: 0;
759	  width: 100%;
760	  height: 100%;
761	  object-fit: cover;
762	  transition: transform var(--transition-slow);
763	  filter: brightness(0.6) saturate(0.7);
