6	/* ------------------------------------------------------------
7	   HAMBURGER BUTTON
8	   ------------------------------------------------------------ */
9	.hamburger {
10	  display: none;
11	  flex-direction: column;
12	  justify-content: center;
13	  align-items: center;
14	  gap: 5px;
15	  width: 36px;
16	  height: 36px;
