1090	  /* ── Waveform rendering ───────────────────────────────────── */
1091	  function drawWave() {
1092	    const dpr  = window.devicePixelRatio || 1;
1093	    const rect = wrapEl.getBoundingClientRect();
1094	    const W    = rect.width;
1095	    const H    = rect.height;
1096	
1097	    canvas.width         = W * dpr;
1098	    canvas.height        = H * dpr;
1099	    canvas.style.width   = W + 'px';
1100	    canvas.style.height  = H + 'px';
