1102	    const ctx = canvas.getContext('2d');
1103	    ctx.scale(dpr, dpr);
1104	    ctx.clearRect(0, 0, W, H);
1105	
1106	    const aActive = S.active === 'a';
1107	    if (BUFS.a) paintChannel(ctx, BUFS.a.getChannelData(0), W, H,
1108	      aActive ? 'rgba(200,146,42,.82)' : 'rgba(200,146,42,.16)');
