1113	  /* Min/max envelope waveform — O(n) single pass */
1114	  function paintChannel(ctx, data, W, H, color) {
1115	    const amp  = H / 2;
1116	    const step = Math.max(1, Math.floor(data.length / W));
1117	    ctx.strokeStyle = color;
1118	    ctx.lineWidth   = 1.5;
1119	    ctx.beginPath();
1120	    for (let x = 0; x < W; x++) {
1121	      let mn = 1, mx = -1;
1122	      const base = x * step;
1123	      const end  = Math.min(base + step, data.length);
1124	      for (let i = base; i < end; i++) {
1125	        const v = data[i];
1126	        if (v < mn) mn = v;
1127	        if (v > mx) mx = v;
1128	      }
1129	      const yT = Math.max(1,     (1 - mx) * amp);
1130	      const yB = Math.min(H - 1, (1 - mn) * amp);
1131	      ctx.moveTo(x + .5, yT);
1132	      ctx.lineTo(x + .5, yB);
1133	    }
1134	    ctx.stroke();
1135	  }
