1137	  /* ── Stream-loading with byte-level progress ──────────────── */
1138	  let pA = 0, pB = 0;
1139	
1140	  function refreshPct() {
1141	    /* Both tracks contribute 50% each to the combined indicator */
1142	    pctEl.textContent = Math.round((pA + pB) / 2 * 100) + '%';
1143	  }
1144	
1145	  async function streamFetch(url, onProgress) {
1146	    const res    = await fetch(url);
1147	    const total  = parseInt(res.headers.get('Content-Length') || '0', 10);
1148	    const reader = res.body.getReader();
1149	    const chunks = [];
1150	    let loaded   = 0;
1151	
1152	    while (true) {
1153	      const { done, value } = await reader.read();
1154	      if (done) break;
1155	      chunks.push(value);
1156	      loaded += value.byteLength;
1157	      /* Report progress only when Content-Length is known */
1158	      if (total > 0) onProgress(loaded / total);
1159	    }
1160	
1161	    /* Assemble into a single contiguous ArrayBuffer */
1162	    const merged = new Uint8Array(loaded);
1163	    let offset   = 0;
1164	    for (const chunk of chunks) { merged.set(chunk, offset); offset += chunk.byteLength; }
1165	    return merged.buffer;
1166	  }
1167	
1168	  async function loadTrack(id, url) {
1169	    if (!url) {
1170	      /* Missing URL → count as "done" for progress purposes */
1171	      if (id === 'a') pA = 1; else pB = 1;
1172	      refreshPct();
1173	      return;
1174	    }
1175	    try {
1176	      const raw = await streamFetch(url, p => {
1177	        if (id === 'a') pA = p; else pB = p;
1178	        refreshPct();
1179	      });
1180	      /* Finalize to exactly 100% */
1181	      if (id === 'a') pA = 1; else pB = 1;
1182	      refreshPct();
1183	
1184	      /* decodeAudioData transfers ownership of the ArrayBuffer — that's fine here */
1185	      BUFS[id] = await audioCtx.decodeAudioData(raw);
1186	    } catch (err) {
1187	      console.warn('[AB-Player] failed to load track', id, err);
1188	    }
1189	  }
