1191	  /* ── Initialisation ───────────────────────────────────────── */
1192	  async function init() {
1193	    if (!URL_A && !URL_B) {
1194	      /* Both URLs empty — show notice, hide loader */
1195	      loadingEl.classList.add('is-ready');
1196	      phEl.textContent = 'Keine Audiodateien konfiguriert.';
