1215	      loadTrack('a', URL_A),
1216	      loadTrack('b', URL_B),
1217	    ]);
1218	
1219	    const ref = BUFS.a || BUFS.b;
1220	    if (!ref) {
1221	      phEl.textContent = 'Ladefehler — bitte Konsole prüfen.';
1222	      return;
1223	    }
1224	
1225	    /* Set duration from first available buffer */
1226	    S.duration          = ref.duration;
1227	    timeDur.textContent = fmt(S.duration);
1228	
1229	    /* Hide loading indicator (CSS transition fades it out) */
1230	    loadingEl.classList.add('is-ready');
1231	
1232	    /* Render waveform */
1233	    phEl.style.display = 'none';
1234	    drawWave();
1235	
1236	    /* Enable controls */
1237	    playBtn.disabled = false;
1238	    seekEl.disabled  = false;
1239	
