2170	async function _processFile(file, wrap) {
2171	  if (!file || !wrap) return;
2172	  const slot = wrap.dataset.slot;
2173	  const specKey = slot;
2174	  const spec = SPECS[specKey];
2175	
2176	  // Validate MIME
2177	  if (!['image/jpeg','image/png'].includes(file.type)) {
2178	    imgErr(`Format nicht erlaubt: ${file.type}. Nur JPG/PNG.`); return;
2179	  }
2180	
2181	  // Validate dimensions client-side
2182	  if (spec) {
2183	    const dims = await new Promise(res => {
2184	      const img = new Image();
2185	      const url = URL.createObjectURL(file);
2186	      img.onload = () => { URL.revokeObjectURL(url); res({w:img.width,h:img.height}); };
2187	      img.onerror= () => { URL.revokeObjectURL(url); res(null); };
2188	      img.src = url;
2189	    });
2190	    if (!dims) { imgErr('Kein gültiges Bild.'); return; }
2191	    const tol = spec.tol ?? 0;
2192	    if (Math.abs(dims.w - spec.w) > tol || Math.abs(dims.h - spec.h) > tol) {
2193	      imgErr(`Falsche Maße: ${dims.w}×${dims.h}px. Erwartet: ${spec.w}×${spec.h}px${tol>0?` (±${tol}px)`:''}. Upload blockiert.`);
2194	      return;
2195	    }
2196	  }
2197	
2198	  // In-place preview
2199	  const reader = new FileReader();
2200	  reader.onload = ev => {
2201	    let imgEl = wrap.querySelector('img');
2202	    if (!imgEl) {
2203	      imgEl = document.createElement('img');
2204	      imgEl.style.cssText = 'width:100%;height:100%;object-fit:cover;display:block;position:absolute;inset:0';
2205	      wrap.querySelector('.ph')?.remove();
2206	      wrap.appendChild(imgEl);
2207	    }
2208	    imgEl.src = ev.target.result;
2209	    // Mark parent box dirty
2210	    const boxEl = wrap.closest('.cms-box');
2211	    if (boxEl) boxEl.classList.add('is-dirty');
2212	  };
2213	  reader.readAsDataURL(file);
2214	
2215	  State.dirtyMedia[slot] = file;
2216	  updateSaveBar();
2217	}
