2257	              body: JSON.stringify({ page_slug:PAGE, fields:{}, media_slot:slot, media_id:j.media.id, csrf_token:CSRF })
2258	            });
2259	          })
2260	      );
2261	    }
2262	
2263	    const results = await Promise.allSettled(tasks);
2264	    const failed  = results.filter(r => r.status==='rejected');
2265	
