2276	  } catch(e) {
2277	    toast('Fehler: ' + e.message, 'err');
2278	  } finally {
2279	    btn.disabled = false;
2280	    btn.innerHTML = btnHTML;
2281	    updateSaveBar();
2282	  }
2283	}
