.fe-hero-tagline{font-family:'Cormorant Garamond',serif;font-style:italic;font-size:clamp(.75rem,1.8vw,1rem);font-weight:300;letter-spacing:.30em;text-transform:uppercase;color:#C8922A}

.fe-section{padding:44px 32px}
.fe-section--dark{background:#0D0D0D}
.fe-section--card{background:#141414}
.fe-section--base{background:#080808}
.fe-sec-label{font-size:.688rem;letter-spacing:.20em;text-transform:uppercase;color:rgba(200,146,42,.55);margin-bottom:6px}
.fe-sec-title{font-family:'Cormorant Garamond',serif;font-size:2rem;font-weight:300;color:#F0EDE8;margin-bottom:22px}

.fe-slideshow{background:#0D0D0D;padding:40px 32px}
.fe-slide-aspect{aspect-ratio:16/7;background:#111;border-radius:12px;overflow:hidden;position:relative;display:flex;align-items:center;justify-content:center;border:1px solid var(--fe-border)}
.fe-slide-ph{font-size:11px;color:rgba(255,255,255,.1);font-family:monospace;letter-spacing:.1em;text-transform:uppercase}
.fe-slide-caption{font-family:'Cormorant Garamond',serif;font-style:italic;font-size:.813rem;color:rgba(200,146,42,.7);margin-top:14px}

/* ── Studio-Photos gallery ─────────────────────────────────────────────── */
.fe-sphotos-scroll{overflow-x:auto;padding-bottom:4px}
.fe-sphotos-scroll::-webkit-scrollbar{height:3px}
.fe-sphotos-scroll::-webkit-scrollbar-track{background:transparent}
.fe-sphotos-scroll::-webkit-scrollbar-thumb{background:#8A6420;border-radius:99px}
.fe-sphotos-track{display:flex;gap:10px;min-height:140px}
.fe-sphoto-item{flex:0 0 200px;display:flex;flex-direction:column;gap:6px}
.fe-sphoto-img{aspect-ratio:3/2;border-radius:8px;overflow:hidden;border:1px solid var(--fe-border);background:#111;position:relative}
.fe-sphoto-cap{font-family:'Cormorant Garamond',serif;font-style:italic;font-size:.75rem;color:rgba(200,146,42,.7);text-align:center;margin:0;padding:0 4px}
/* Add/remove bar — only visible while gear is active (is-editing) */
.studio-photos-bar{display:none;align-items:center;gap:8px;padding:9px 12px;background:rgba(6,6,4,.95);border-top:1px solid rgba(200,146,42,.15)}
.cms-box.is-editing .studio-photos-bar{display:flex}
.studio-photos-bar-label{flex:1;font-size:11px;color:rgba(240,237,232,.35);font-family:'Inter',sans-serif}
.spb-btn{padding:5px 11px;border-radius:5px;font-size:12px;font-weight:500;cursor:pointer;border:1px solid rgba(200,146,42,.4);font-family:'Inter',sans-serif;background:rgba(200,146,42,.08);color:#C8922A;transition:all .15s}
.spb-btn:hover:not(:disabled){background:rgba(200,146,42,.22);border-color:#C8922A}
.spb-btn:disabled{opacity:.3;cursor:not-allowed}

/* ── Sessions extras ─────────────────────────────────────────────────────── */
.fe-pkg-grid{display:grid;grid-template-columns:1fr 1fr;gap:8px}
.fe-pkg-card{background:rgba(14,14,12,.7);border:1px solid rgba(255,255,255,.06);border-radius:12px;overflow:hidden}
.fe-pkg-head{padding:1.25rem 1.5rem 1rem;border-bottom:1px solid rgba(255,255,255,.05);display:flex;justify-content:space-between;align-items:flex-start;gap:1rem}
.fe-pkg-name{font-family:'Cormorant Garamond',serif;font-size:1.1rem;color:#F0EDE8;margin-bottom:.25rem}
.fe-pkg-sub{font-size:.625rem;letter-spacing:.12em;text-transform:uppercase;color:rgba(200,146,42,.7)}
.fe-pkg-price{font-family:'Cormorant Garamond',serif;font-size:1.4rem;color:#F0EDE8;text-align:right;line-height:1.1}
.fe-pkg-pnote{font-size:.575rem;letter-spacing:.10em;text-transform:uppercase;color:rgba(255,255,255,.22);text-align:right;margin-top:.2rem}
.fe-pkg-body{padding:1rem 1.5rem 1.25rem}
.fe-pkg-desc{font-size:.813rem;color:rgba(168,164,158,.85);line-height:1.7;margin-bottom:.75rem}
.fe-pkg-inc{font-size:.75rem;color:rgba(168,164,158,.75);padding:.18rem 0 .18rem .9rem;position:relative;line-height:1.4}
.fe-pkg-inc::before{content:'✓';position:absolute;left:0;color:#C8922A;font-size:.65rem;top:.22rem}
.fe-notice{background:rgba(200,146,42,.06);border:1px solid rgba(200,146,42,.18);border-radius:10px;padding:1rem 1.5rem;font-size:.813rem;color:rgba(168,164,158,.9);line-height:1.7;margin-top:8px}
.fe-faq-item{border-bottom:1px solid rgba(255,255,255,.05);padding:.75rem 0}
.fe-faq-q{font-family:'Cormorant Garamond',serif;font-size:1rem;color:#F0EDE8;margin-bottom:.3rem}
.fe-faq-a{font-size:.813rem;font-weight:300;color:rgba(168,164,158,.85);line-height:1.75}
.fe-s-cta{display:flex;justify-content:space-between;align-items:center;gap:2rem;padding:1.75rem 2rem;background:rgba(14,14,12,.8);border-radius:14px}
.fe-s-cta-left{flex:1}
.fe-s-cta-title{font-family:'Cormorant Garamond',serif;font-size:1.5rem;color:#F0EDE8;line-height:1.2;margin-bottom:.5rem}
.fe-s-cta-desc{font-size:.838rem;color:rgba(168,164,158,.85);line-height:1.7}
.fe-s-cta-btn{padding:.6rem 1.25rem;background:#3A7BD5;color:#fff;border-radius:7px;font-size:.75rem;font-weight:500;letter-spacing:.08em;text-transform:uppercase;white-space:nowrap;flex-shrink:0}

.fe-about-glass{background:rgba(20,20,20,.6);border:1px solid var(--fe-border);border-radius:16px;padding:44px}
.fe-about-label{font-size:.688rem;letter-spacing:.25em;text-transform:uppercase;color:#C8922A;margin-bottom:.75rem}
.fe-about-title{font-family:'Cormorant Garamond',serif;font-size:clamp(1.75rem,3.5vw,2.75rem);font-weight:300;line-height:1.15;color:#F0EDE8;margin-bottom:2rem}
.fe-about-divider{height:1px;background:linear-gradient(to right,rgba(200,146,42,.3),transparent);margin-bottom:2rem}
.fe-about-grid{display:grid;grid-template-columns:1.2fr 1fr;gap:40px}
.fe-about-p{font-size:.938rem;line-height:1.7;color:rgba(240,237,232,.7);margin-bottom:1rem}
.fe-hl{padding:10px 0;border-bottom:1px solid var(--fe-border)}
.fe-hl-label{font-size:10px;letter-spacing:.12em;text-transform:uppercase;color:#C8922A;margin-bottom:4px}
.fe-hl-val{font-size:13px;color:rgba(240,237,232,.8)}

.fe-contact-grid{display:grid;grid-template-columns:1fr 1fr;gap:48px;align-items:center}
.fe-contact-title{font-family:'Cormorant Garamond',serif;font-size:clamp(1.75rem,3.5vw,2.75rem);font-weight:300;line-height:1.2;color:#F0EDE8;margin-bottom:1.2rem}
.fe-contact-desc{font-size:.938rem;color:rgba(240,237,232,.6);line-height:1.7}
.fe-form-mock{background:#111;border:1px solid var(--fe-border);border-radius:8px;padding:12px 14px;font-size:13px;color:rgba(240,237,232,.3);margin:8px 0 12px}
.fe-submit-mock{display:inline-block;background:#C8922A;color:#000;border-radius:9999px;padding:10px 28px;font-size:12px;font-weight:600;opacity:.7}

.fe-page-hero{padding:52px 32px 32px;background:#0D0D0D;border-bottom:1px solid var(--fe-border)}
.fe-ph-label{font-size:.688rem;letter-spacing:.20em;text-transform:uppercase;color:rgba(200,146,42,.55);margin-bottom:8px}
.fe-ph-title{font-family:'Cormorant Garamond',serif;font-size:3rem;font-weight:300;color:#F0EDE8;margin-bottom:8px}
.fe-ph-sub{font-size:.875rem;color:rgba(240,237,232,.5)}

.fe-services-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:14px}
.fe-scard{background:var(--fe-surface);border:1px solid var(--fe-border);border-radius:12px;padding:22px;position:relative}
.fe-scard--feat{border-color:rgba(200,146,42,.3);background:linear-gradient(135deg,var(--fe-surface),#1f1c14)}
.fe-badge{display:inline-block;font-size:10px;font-weight:600;letter-spacing:.08em;text-transform:uppercase;color:#C8922A;border:1px solid rgba(200,146,42,.4);border-radius:9999px;padding:2px 10px;margin-bottom:10px}
.fe-scard-title{font-family:'Cormorant Garamond',serif;font-size:1.3rem;color:#F0EDE8;margin-bottom:6px}
.fe-scard-desc{font-size:.813rem;color:rgba(240,237,232,.6);line-height:1.6;margin-bottom:10px}
.fe-feat-line{font-size:.72rem;color:rgba(240,237,232,.5);padding:4px 0;border-bottom:1px solid rgba(255,255,255,.04)}
.fe-price-block{margin-top:14px;padding-top:12px;border-top:1px solid rgba(255,255,255,.06)}
.fe-price-row{display:flex;align-items:baseline;gap:6px}
.fe-price-amount{font-family:'Cormorant Garamond',serif;font-size:1.8rem;font-weight:300;color:#C8922A}
.fe-price-unit{font-size:12px;color:rgba(240,237,232,.5)}
.fe-price-note{font-size:11px;color:rgba(240,237,232,.35);margin-top:4px}
.fe-price-hidden{font-size:11.5px;color:rgba(240,237,232,.25);font-style:italic;margin-top:14px}
.fe-price-on-req{font-family:'Cormorant Garamond',serif;font-size:1.1rem;color:rgba(200,146,42,.7);margin-top:14px}

.fe-rooms-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:12px}
.fe-room-card{background:var(--fe-surface);border:1px solid var(--fe-border);border-radius:10px;overflow:hidden}
.fe-room-img{height:120px;background:#222;position:relative;overflow:hidden}
.fe-room-img img,.fe-room-img .ph{width:100%;height:100%;object-fit:cover}
.fe-room-img .ph{display:flex;align-items:center;justify-content:center;font-size:10px;color:rgba(255,255,255,.15);font-family:monospace}
.fe-room-body{padding:14px}
.fe-room-tag{display:inline-block;font-size:10px;letter-spacing:.10em;text-transform:uppercase;color:#C8922A;border:1px solid rgba(200,146,42,.3);border-radius:9999px;padding:2px 10px;margin-bottom:8px}
.fe-room-title{font-family:'Cormorant Garamond',serif;font-size:1.2rem;color:#F0EDE8;margin-bottom:3px}
.fe-room-sub{font-size:11px;color:rgba(200,146,42,.7);margin-bottom:6px}
.fe-room-desc{font-size:.75rem;color:rgba(240,237,232,.5);line-height:1.6}

.fe-eq-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:12px}
.fe-eq-card{background:var(--fe-surface);border:1px solid var(--fe-border);border-radius:10px;overflow:hidden}
.fe-eq-img{height:100px;background:#222;position:relative;overflow:hidden}
.fe-eq-img img,.fe-eq-img .ph{width:100%;height:100%;object-fit:cover}
.fe-eq-img .ph{display:flex;align-items:center;justify-content:center;font-size:10px;color:rgba(255,255,255,.15);font-family:monospace}
.fe-eq-body{padding:12px}
.fe-eq-cat{font-size:10px;letter-spacing:.12em;text-transform:uppercase;color:#C8922A;margin-bottom:4px}
.fe-eq-name{font-family:'Cormorant Garamond',serif;font-size:1.05rem;color:#F0EDE8}

.fe-special-card{display:grid;grid-template-columns:1fr 1.3fr;background:#141414;border:1px solid var(--fe-border);border-radius:12px;overflow:hidden;margin-bottom:12px}
.fe-special-img{background:var(--fe-surface);min-height:180px;position:relative;overflow:hidden}
.fe-special-img img,.fe-special-img .ph{width:100%;height:100%;object-fit:cover;min-height:180px}
.fe-special-img .ph{display:flex;align-items:center;justify-content:center;font-size:10px;color:rgba(255,255,255,.15);font-family:monospace}
.fe-special-body{padding:24px}
.fe-special-title{font-family:'Cormorant Garamond',serif;font-size:1.3rem;color:#F0EDE8;margin-bottom:8px}
.fe-special-desc{font-size:.813rem;color:rgba(240,237,232,.6);line-height:1.6;margin-bottom:12px}
.fe-si-line{font-size:.72rem;color:rgba(240,237,232,.5);padding:3px 0}

.fe-artist-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:10px}
.fe-artist-card{background:var(--fe-surface);border:1px solid var(--fe-border);border-radius:10px;overflow:hidden}
.fe-artist-img{height:88px;background:#222;position:relative;overflow:hidden}
.fe-artist-img img,.fe-artist-img .ph{width:100%;height:100%;object-fit:cover}
.fe-artist-img .ph{display:flex;align-items:center;justify-content:center;font-size:10px;color:rgba(255,255,255,.15);font-family:monospace}
.fe-artist-name{font-size:12px;font-weight:500;color:#F0EDE8;padding:8px 10px 3px}
.fe-artist-genre{font-size:10px;color:#C8922A;padding:0 10px 5px}
.fe-artist-desc{font-size:10px;color:rgba(168,164,158,.6);padding:0 10px 8px;line-height:1.5}
.fe-company-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:8px;margin-top:10px}
.fe-company-item{background:var(--fe-surface);border:1px solid var(--fe-border);border-radius:8px;padding:12px 14px;display:flex;align-items:center;gap:10px}
.fe-company-icon{width:32px;height:32px;background:rgba(255,255,255,.04);border:1px solid var(--fe-border);border-radius:7px;display:flex;align-items:center;justify-content:center;font-family:'Cormorant Garamond',serif;font-size:1rem;color:rgba(200,146,42,.7);flex-shrink:0}
.fe-company-name{font-size:12px;font-weight:500;color:#F0EDE8;margin-bottom:2px}
.fe-company-type{font-size:10px;color:rgba(200,146,42,.55);letter-spacing:.08em;text-transform:uppercase}
.fe-video-banner{display:flex;align-items:center;gap:14px;background:var(--fe-surface);border:1px solid var(--fe-border);border-radius:12px;padding:16px 20px}
.fe-video-title{font-size:13px;font-weight:500;color:#F0EDE8;margin-bottom:3px}
.fe-video-sub{font-size:11px;color:rgba(168,164,158,.6)}
.fe-video-url{font-size:10px;color:rgba(200,146,42,.55);font-family:monospace;word-break:break-all;flex:1;padding:0 12px;opacity:.7}
.fe-video-btn{background:rgba(255,255,255,.04);color:rgba(240,237,232,.7);border:1px solid var(--fe-border);border-radius:9999px;padding:6px 14px;font-size:11px;font-weight:500;white-space:nowrap;flex-shrink:0}
.fe-ar-list{display:flex;flex-direction:column;gap:6px;max-height:640px;overflow-y:auto;padding-right:2px}
.fe-ar-row{display:flex;align-items:flex-start;gap:10px;background:var(--fe-surface);border:1px solid var(--fe-border);border-radius:8px;padding:10px}
.fe-ar-photo{width:84px;height:84px;flex-shrink:0;border-radius:6px;overflow:hidden;background:#111;position:relative;cursor:pointer}
.fe-ar-photo>.cms-img-wrap{position:absolute;inset:0;width:auto!important;height:auto!important}
.fe-ar-photo .ph{position:absolute;inset:0;display:flex;align-items:center;justify-content:center;font-size:8px;color:rgba(255,255,255,.15);font-family:monospace;text-align:center;padding:4px;line-height:1.4}
.fe-ar-fields{display:flex;flex-direction:column;gap:4px;flex:1;min-width:0}
.fe-ar-top{display:flex;align-items:center;gap:6px;flex-wrap:nowrap;overflow:hidden}
.fe-ar-num{font-size:9px;color:rgba(255,255,255,.2);min-width:14px;font-family:monospace;flex-shrink:0}
.fe-ar-feat-sel{font-size:10px;border-radius:4px;padding:2px 5px;height:20px;flex-shrink:0;max-width:105px}
.fe-ar-name{font-size:12px;font-weight:500;color:#F0EDE8;flex:1;min-width:0;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}
.fe-ar-genre{font-size:10px;color:#C8922A;flex-shrink:0;white-space:nowrap}
.fe-ar-desc{font-size:11px;color:rgba(168,164,158,.6);line-height:1.55;margin-top:2px}
.fe-ar-spotify{font-size:9px;color:rgba(29,185,84,.6);font-family:monospace;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;margin-top:1px}
/* Edit-Modus: Top-Zeile kompakt halten — Inputs als Flex-Items, kein Wrap */
.cms-box.is-editing .fe-ar-top>.edit-mode{display:flex;align-items:center;gap:2px;min-width:0;flex-shrink:1}
.cms-box.is-editing .fe-ar-top>[data-field-em$=".name"].edit-mode{flex:1;min-width:80px}
.cms-box.is-editing .fe-ar-top>[data-field-em$=".genre"].edit-mode{flex:1;min-width:60px}
.fe-ar-top .cms-cnt{display:none}
.fe-ar-top .cms-inp{width:100%;min-width:0;box-sizing:border-box}
.fe-co-list{display:flex;flex-direction:column;gap:4px}
.fe-co-row{display:flex;align-items:center;gap:10px;background:var(--fe-surface);border:1px solid var(--fe-border);border-radius:8px;padding:9px 12px}
.fe-co-fields{display:flex;flex-direction:column;gap:3px;flex:1;min-width:0}

.fe-spotify{background:linear-gradient(135deg,var(--fe-surface),#111811);border:1px solid rgba(30,215,96,.2);border-radius:12px;padding:18px 22px;display:flex;align-items:center;justify-content:center;gap:18px;margin-bottom:22px}
.fe-spotify-icon{width:38px;height:38px;background:#1DB954;border-radius:50%;display:flex;align-items:center;justify-content:center;flex-shrink:0}
.fe-spotify-title{font-size:13px;font-weight:600;color:#F0EDE8;margin-bottom:2px}
.fe-spotify-sub{font-size:11px;color:rgba(240,237,232,.5)}
.fe-spotify-btn{background:#1DB954;color:#000;border-radius:9999px;padding:7px 18px;font-size:11.5px;font-weight:600;white-space:nowrap}

.fe-wizard{background:var(--fe-surface);border:1px solid var(--fe-border);border-radius:12px;padding:28px}
.fe-steps{display:flex;align-items:center;gap:0}
.fe-step{display:flex;flex-direction:column;align-items:center;gap:5px}
.fe-step-circle{width:34px;height:34px;border-radius:50%;background:rgba(200,146,42,.2);border:1px solid rgba(200,146,42,.4);display:flex;align-items:center;justify-content:center;font-size:12px;font-weight:600;color:#C8922A}
.fe-step-label{font-size:10px;letter-spacing:.08em;text-transform:uppercase;color:rgba(240,237,232,.4);white-space:nowrap}
.fe-step-line{flex:1;height:1px;background:rgba(255,255,255,.08);margin:0 8px 18px}
/* ── Booking Tool-Karten (iCal-Checker) ─────────────────────────────────── */
.cms-bk-tool-card{background:var(--bg-surface);border:1px solid var(--border);border-radius:var(--r-lg);padding:14px 16px}
.cms-bk-tool-title{font-size:11px;font-weight:600;color:var(--text-secondary);text-transform:uppercase;letter-spacing:.08em;margin-bottom:10px}
.cms-bk-tool-row{display:flex;align-items:center;justify-content:space-between;gap:10px}
.cms-bk-tool-lbl{font-size:12px;color:var(--text-muted)}
/* ── Booking Step Boxes ─────────────────────────────────────────────────── */
.fe-bk-card{background:var(--fe-surface);border:1px solid var(--fe-border);border-radius:10px;overflow:hidden;margin-bottom:10px}
.fe-bk-head{display:flex;align-items:center;gap:12px;padding:14px 18px;border-bottom:1px solid var(--fe-border)}
.fe-bk-num{width:32px;height:32px;border-radius:50%;background:rgba(200,146,42,.15);border:1px solid rgba(200,146,42,.35);display:flex;align-items:center;justify-content:center;font-size:13px;font-weight:600;color:#C8922A;flex-shrink:0}
.fe-bk-meta{flex:1;min-width:0}
.fe-bk-lbl{font-size:9px;color:rgba(200,146,42,.55);letter-spacing:.14em;text-transform:uppercase;margin-bottom:2px}
.fe-bk-ttl{font-family:'Cormorant Garamond',serif;font-size:1.15rem;font-weight:300;color:#F0EDE8}
.fe-bk-body{padding:14px 18px}
.fe-bk-foot{padding:10px 18px;border-top:1px solid var(--fe-border);display:flex;justify-content:flex-end}
.fe-bk-nav-btn{background:#3A7BD5;color:#fff;border-radius:9999px;padding:5px 16px;font-size:11px;font-weight:500;white-space:nowrap}
/* Service option grid */
.fe-svc-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:6px;margin-bottom:2px}
.fe-svc-opt{background:rgba(255,255,255,.025);border:1px solid var(--fe-border);border-radius:8px;padding:10px 12px}
.fe-svc-title{font-size:12px;font-weight:500;color:#F0EDE8;margin-bottom:3px}
.fe-svc-sub{font-size:10px;color:rgba(168,164,158,.5);line-height:1.4}
/* Info / privacy boxes */
.fe-bk-info{background:rgba(255,255,255,.02);border:1px solid rgba(255,255,255,.06);border-radius:8px;padding:11px 14px;margin-bottom:6px}
.fe-bk-info-lbl{font-size:9px;font-weight:600;color:rgba(200,146,42,.55);letter-spacing:.12em;text-transform:uppercase;margin-bottom:5px}
.fe-bk-info-txt{font-size:11px;color:rgba(168,164,158,.65);line-height:1.6}
/* Ghost form rows */
.fe-bk-ghost{display:grid;gap:5px;margin-bottom:10px;opacity:.35}
.fe-bk-ghost-row{display:grid;grid-template-columns:1fr 1fr;gap:5px}
.fe-bk-ghost-field{height:30px;background:rgba(255,255,255,.04);border:1px solid rgba(255,255,255,.06);border-radius:6px}
/* Success preview */
