2080	'use strict';
2081	
2082	/* ── State ── */
2083	const State = {
2084	  openBox:    null,       // box id currently editing
2085	  origValues: {},         // fieldKey → original text (for cancel)
2086	  dirty:      {},         // fieldKey → new value (staged, not yet in DB)
2087	  dirtyMedia: {},         // slotKey  → File
2088	};
2089	
2090	/* ── Helpers ── */
2091	function $b(id) { return document.getElementById('box-' + id); }
2092	function toast(msg, type='ok', ms=3000) {
2093	  const t = document.createElement('div');
2094	  t.className = 'st-item' + (type==='err'?' err':'');
2095	  t.textContent = msg;
2096	  document.getElementById('save-toast').appendChild(t);
2097	  setTimeout(() => { t.style.opacity='0'; t.style.transition='opacity .2s'; setTimeout(()=>t.remove(),200); }, ms);
2098	}
2099	function imgErr(msg) {
2100	  const el = document.getElementById('img-err');
2101	  el.textContent = msg; el.style.display='block';
2102	  setTimeout(() => el.style.display='none', 5000);
2103	}
2104	
2105	/* ── Save bar ── */
2106	function updateSaveBar() {
2107	  const dc = Object.keys(State.dirty).length + Object.keys(State.dirtyMedia).length;
2108	  document.getElementById('save-info').textContent  = dc ? `${dc} ungespeicherte Änderung${dc!==1?'en':''}` : 'Keine Änderungen';
2109	  document.getElementById('save-info').className    = 'save-info' + (dc ? ' has-changes' : '');
2110	  document.getElementById('btn-save').className     = dc ? 'on' : '';
2111	  document.getElementById('btn-discard').className  = dc ? 'on' : '';
2112	  window.onbeforeunload = dc ? () => 'Ungespeicherte Änderungen vorhanden.' : null;
2113	}
2114	
2115	/* ── Box gear click ── */
2116	function boxGear(id) {
2117	  if (State.openBox && State.openBox !== id) boxCancel(State.openBox);
2118	  if (State.openBox === id) { boxCancel(id); return; }

